import java.util.*;
import java.io.*;
import java.math.*;


class Solution {

    public static void main(String args[]) {
        Scanner in = new Scanner(System.in);
        int valeur1 = in.nextInt();
        int valeur2 = in.nextInt();
        System.out.println(valeur1 * 5 - valeur2 * 3 + 2);
    }
}

